    return _make_shim(
        tmp_path,
        """
        def probe(server, **kwargs):
            return False

        def call_tool(server, tool, args):
            raise RuntimeError("shim: should not be called when probe is False")

        class McpUnreachable(Exception): pass
        class McpToolError(Exception): pass
        """,
    )


