def test_fires_and_calls_create_entities(
    review_dir: Path, shim_succeeds: tuple[Path, Path]
) -> None:
    shim_path, capture_path = shim_succeeds
    _write_review(review_dir, _high_signal_review())
    result = _run(review_dir, pythonpath=shim_path)
    assert result.returncode == 0, f"stderr: {result.stderr}"
    assert "signal fired" in result.stdout

    handoff = _load_handoff(review_dir)
    assert handoff["status"] == "fired"
    assert handoff["verdict"] == "approve"
    assert handoff["repo"] == "yonatangross/orchestkit"
    assert handoff["pr_number"] == 1889
    assert handoff["entity_type"] == "pr-review"
    assert handoff["entity_name"] == "review::yonatangross/orchestkit#1889@2026-05-20T12-00-00Z"
    assert handoff["observations_count"] >= 4  # verdict + pr + changed_paths + 2 findings

    # Verify the actual create_entities payload was right.
    captured = json.loads(capture_path.read_text(encoding="utf-8"))
    assert captured["tool"] == "create_entities"
    entities = captured["args"]["entities"]
    assert len(entities) == 1
    entity = entities[0]
    assert entity["entityType"] == "pr-review"
    obs = entity["observations"]
    assert "verdict=approve" in obs
    assert "pr=yonatangross/orchestkit#1889" in obs
    # changed_paths should be sorted-deduped CSV.
    assert any(o.startswith("changed_paths=") for o in obs)
    csv_obs = next(o for o in obs if o.startswith("changed_paths="))
    paths = csv_obs.removeprefix("changed_paths=").split(",")
    assert paths == sorted(paths)
    assert "finding[praise]=Clear skip semantics." in obs
    assert "finding[suggestion]=Consider lowering log verbosity." in obs


